from maspy import *

class MarketEnv(Environment):
    def __init__(self, env_name=None):
        super().__init__(env_name)
        self.stock = {"apple": 1}

    def request_item(self, agt, item):
        price = self.get_price(item)
        if self.stock[item] > 0:
            self.send(agt, tell, Belief("price", (item, price)))

    def sell_item(self, agt, item):
        if self.stock[item] > 0:
            self.stock[item] -= 1
            self.send(agt, tell, Belief("sold", (item,)))
        else:
            self.send(agt, tell, Belief("out_of_stock", (item,)))

    def get_price(self, item):
        return 8  # Fixed price for simplicity

class Buyer(Agent):
    def __init__(self, env, agent_name=None):
        super().__init__(agent_name)
        self.add(Goal("request_item", ("apple",)), adds_event=False)

    @pl(gain, Goal("request_item", Any))
    def request_item(self, src, item):
        env.request_item(self, item)

    @pl(gain, Belief("price", Any))
    def receive_price(self, src, item, price):
        budget = self.get(Belief("budget")).values[0]
        if price <= budget:
            self.send(src, achieve, Goal("sell_item", (item,)))

    @pl(gain, Belief("sold", Any))
    def item_sold(self, src, item):
        self.add(Belief("owns", (item,)), adds_event=False)
        self.print(f"Bought {item}")
        self.stop_cycle()

    @pl(gain, Belief("out_of_stock", Any))
    def out_of_stock(self, src, item):
        self.print(f"{item} is out of stock")
        self.stop_cycle()

class Seller(Agent):
    def __init__(self, env, agent_name=None):
        super().__init__(agent_name)

    @pl(gain, Goal("sell_item", Any))
    def sell_item(self, src, item):
        env.sell_item(src, item)

    @pl(gain, Belief("sold", Any))
    def item_sold(self, src, item):
        self.rm(Belief("stock", (item, 1)))
        self.add(Belief("stock", (item, 0)), adds_event=False)
        self.print(f"Sold {item}")

    @pl(gain, Belief("out_of_stock", Any))
    def out_of_stock(self, src, item):
        self.print(f"{item} is out of stock")

if __name__ == "__main__":
    env = MarketEnv()
    buyer = Buyer(env, "Buyer")
    seller = Seller(env, "Seller")
    buyer.add(Belief("budget", (10,)), adds_event=False)
    Admin().connect_to([buyer, seller], env)
    Admin().start_system()

