        super().__init__(env_name)
        self.create(Percept("coin", (1,), adds_event=False))
        self.create(Percept("coin", (2,), adds_event=False))
        self.create(Percept("coin", (3,), adds_event=False))

    def collect_coin(self, agt, coin_id):
        coin = self.get(Percept("coin", (coin_id,)))
        if coin:
            self.change(coin, (coin_id, "collected"))
            return True
        else:
            return None

class Collector(Agent):
    def __init__(self, agent_name=None):
        super().__init__(agent_name)
        self.add(Belief("coin_count", (0,)))
        self.add(Goal("collect", (3,)))

    @pl(gain, Goal("collect", (Any,)), Belief("coin_count", (Any,)))
    def collect_coin(self, src, target, coin_count):
        if coin_count < target:
            coin = self.env.get(Percept("coin", (1,)))
            if coin and coin.values[1] == "free":
                self.env.collect_coin(self.name, coin.values[0])
                self.add(Belief("has_coin", (coin.values[0],)))
                self.rm(Belief("coin_count", (coin_count,)))
                self.add(Belief("coin_count", (coin_count + 1,)))
                self.add(Goal("collect", (target,)))
        else:
            self.stop_cycle()

if __name__ == "__main__":
    env = CoinWorld("CoinWorld")
    agent = Collector("Collector")
    Admin().connect_to([agent], env)
    Admin().start_system()

