class PatrolWorld(Environment):
    def __init__(self, env_name=None):
        super().__init__(env_name)
        self.patrol_points = [0, 1, 2, 3]
        self.create(Percept("alert", (False,), adds_event=False))

    def trigger_alert(self):
        alert = self.get(Percept("alert", (False,)))
        if alert:
            self.change(alert, (True,))

class PatrolAgent(Agent):
    def __init__(self, agent_name=None):
        super().__init__(agent_name)
        self.add(Belief("current_point", 0, adds_event=False))
        self.add(Goal("move_to_next_point"))

    @pl(gain, Goal("move_to_next_point"), Belief("current_point", Any))
    def move_to_next_point(self, src, current_point):
        next_point = (current_point + 1) % len(self.env.patrol_points)
        self.env.create(Percept("moved_to", next_point, adds_event=True))
        self.add(Belief("current_point", next_point, adds_event=False))

        if next_point == 0:
            self.env.trigger_alert()

if __name__ == "__main__":
    env = PatrolWorld()
    agent = PatrolAgent()
    env.register_agent(agent)
    env.start()

from maspy import *

class Buyer(Agent):
    def __init__(self, agent_name=None):
        super().__init__(agent_name)
        self.add(Belief("budget", (1000, 2000), adds_event=False))
        self.add(Goal("buy"))

    @pl(gain, Goal("buy"))
    def ask_for_trip(self, src):
        trips = self.env.get(Percept("trip"))
        if trips:
            for trip in trips:
                if trip['attributes']['price'] <= self.beliefs["budget"][1]:
                    self.send(trip['seller'], achieve, Goal("buy", trip['attributes']), "Trip")
                    return
        self.send(src, achieve, Goal("improve"), "Trip")

class Seller(Agent):
    def __init__(self, agent_name=None):
        super().__init__(agent_name)
        self.add(Goal("announce"))

    @pl(gain, Goal("announce"))
    def create_trips(self, src):
        for _ in range(5):
            stops = randint(0, 6)
            price = randint(int(700 / (stops + 1)), 1000)
            trip = (stops, price)
            self.env.announce_trip(trip)

    @pl(gain, Goal("buy", Any))
    def trip_bought(self, src, trip):
        if self.has(Belief("trip", trip)):
            self.env.delist_trip(trip)
            self.send(src, tell, Belief("travel_ticket", trip))
        else:
            self.send(src, achieve, Goal("improve"), "Trip")

class Trip(Environment):
    def announce_trip(self, agt, trip):
        self.print(f"Trip announced by {agt}: {trip}")
        self.create(Percept("trip", {"seller": agt, "attributes": trip}))

    def delist_trip(self, agt, trip):
        self.print(f"Trip delisted by {agt}: {trip['attributes']}")
        trip_perc = self.get(Percept("trip", trip))
        self.delete(trip_perc)

# Create environment and agents
env = Trip()
buyer = Buyer("Buyer")
seller = Seller("Seller")

# Connect agents to environment
Admin().connect_to([buyer, seller], env)

# Start the system
Admin().start_system()

