class Room(Environment):
    def __init__(self, env_name=None):
        super().__init__(env_name)
        self.create(Percept("room", ("available", True), adds_event=False))

    def book_room(self, agt):
        room = self.get(Percept("room", ("available", True)))
        if room:
            self.change(room, ("available", False))
            return True
        else:
            return False

    def cancel_booking(self, agt):
        room = self.get(Percept("room", ("available", False)))
        if room:
            self.change(room, ("available", True))
            return True
        else:
            return False

class Guest(Agent):
    def __init__(self, agent_name=None):
        super().__init__(agent_name)
        self.add(Belief("needs_room", True, adds_event=False))
        self.add(Goal("book"))

    @pl(gain, Goal("book"), Belief("needs_room", True))
    def book_room(self, src):
        room_env = Room()
        if room_env.book_room(self.name):
            self.rm(Belief("needs_room", True))
            self.add(Belief("in_room", True, adds_event=False))
            self.send(src, tell, Belief("room_booked", True))
        else:
            self.send(src, achieve, Goal("find_another_room"))

class Host(Agent):
    def __init__(self, agent_name=None):
        super().__init__(agent_name)
        self.add(Goal("cancel"))

    @pl(gain, Goal("cancel"), Belief("in_room", True))
    def cancel_booking(self, src):
        room_env = Room()
        if room_env.cancel_booking(self.name):
            self.rm(Belief("in_room", True))
            self.add(Belief("needs_room", True, adds_event=False))
            self.send(src, tell, Belief("room_cancelled", True))
        else:
            self.send(src, achieve, Goal("find_another_room"))

