class CoinWorld(Environment):
    def __init__(self):
        super().__init__()
        self.coins = []
        self.coin_count = 0

    def add_coin(self, coin_id):
        self.coins.append(coin_id)
        self.coin_count += 1
        self.add(Belief("coin_count", (self.coin_count,)))

    def remove_coin(self, coin_id):
        if coin_id in self.coins:
            self.coins.remove(coin_id)
            self.coin_count -= 1
            self.add(Belief("coin_count", (self.coin_count,)))

class Collector(Agent):
    def __init__(self, env):
        super().__init__(env)
        self.env = env
        self.env.add(Belief("coin_count", (0,)))
        self.env.add(Goal("collect", (3,)))

    @pl(gain, Goal("collect"), Belief("coin_count", (Any,)))
    def collect_coin(self, src, coin_count):
        if coin_count < 3:
            coin_id = self.env.get_percept("coin")
            self.env.remove_coin(coin_id)
            self.env.add(Belief("has_coin", (coin_id,)))
            self.env.change(Goal("collect"), (coin_count + 1,))
        else:
            self.stop_cycle()

