        self.patrol_points = [0, 1, 2, 3]
        self.current_point = 0
        self.intruder_detected = False

    def move_to_next_point(self):
        if self.current_point < len(self.patrol_points) - 1:
            self.current_point += 1
            return True
        return False

    def detect_intruder(self):
        self.intruder_detected = True

class Guard(Agent):
    def __init__(self, env):
        super().__init__(env)
        self.env = env
        self.env.add(Belief("patrol_point", (0,)))
        self.env.add(Belief("alert_sent", (False,)))
        self.env.add(Goal("patrol", ()))

    @pl(gain, Goal("patrol"), Belief("alert_sent", (False,)))
    def patrol(self, src, alert_sent):
        if not self.env.intruder_detected:
            next_point = self.env.current_point
            self.env.rm(Belief("patrol_point", (next_point,)))
            next_point = (next_point + 1) % len(self.env.patrol_points)
            self.env.add(Belief("patrol_point", (next_point,)))
        else:
            self.env.rm(Goal("patrol"))
            self.env.add(Belief("alert_sent", ("sent",)))
            self.stop_cycle()

