from maspy import *

class DeliveryWorld(Environment):
    def __init__(self):
        self.package_locations = {
            "depot": ["package1", "package2"],
            "location1": [],
            "location2": []
        }
        self.delivery_destinations = {
            "package1": "location1",
            "package2": "location2"
        }

    def pick_up_package(self, package_id):
        if package_id in self.package_locations["depot"]:
            self.package_locations["depot"].remove(package_id)
            return True
        return False

    def deliver_package(self, package_id, location):
        if location in self.delivery_destinations and package_id == self.delivery_destinations[package_id]:
            self.package_locations[location].append(package_id)
            return True
        return False

class Courier(Agent):
    def __init__(self, env):
        super().__init__(env)
        self.env = env
        self.add(Belief("delivered_count", (0,)))
        self.add(Belief("at_location", ("depot",)))
        self.add(Goal("deliver_packages", (2,)))

    @pl(gain, Goal("deliver_packages"), [Belief("delivered_count", (Any,)), Belief("at_location", ("depot",))])
    def deliver_packages(self, src, target, delivered_count, at_location):
        if delivered_count < 2:
            package_id = self.env.package_locations["depot"][0]
            self.env.pick_up_package(package_id)
            self.add(Belief("current_package", (package_id,)))
            self.add(Goal("travel_to_delivery_location"))
        else:
            self.stop_cycle()

    @pl(gain, Goal("travel_to_delivery_location"), [Belief("current_package", (Any,))])
    def travel_to_delivery_location(self, src, current_package):
        location = self.env.delivery_destinations[current_package]
        self.rm(Belief("at_location", ("depot",)))
        self.add(Belief("at_location", (location,)))
        self.add(Goal("deliver_package"))

    @pl(gain, Goal("deliver_package"), [Belief("current_package", (Any,)), Belief("at_location", (Any,))])
    def deliver_package(self, src, current_package, at_location):
        if self.env.deliver_package(current_package, at_location):
            self.add(Belief("delivered_package", (current_package,)))
            self.rm(Belief("delivered_count", (Any,)))
            self.add(Belief("delivered_count", (self.env.package_locations[at_location].count(current_package),)))
            self.rm(Belief("at_location", (at_location,)))
            self.add(Belief("at_location", ("depot",)))
            self.add(Goal("deliver_packages"))

if __name__ == "__main__":
    env = DeliveryWorld()
    courier = Courier(env)
    Admin().connect_to([courier], env)
    Admin().start_system()

from maspy import *

class PatrolWorld(Environment):
    def __init__(self):
        self.patrol_points = [0, 1, 2, 3]
        self.current_patrol_point = 0
        self.intruder_detected = False

    def move_to_next_patrol_point(self):
        self.current_patrol_point = (self.current_patrol_point + 1) % len(self.patrol_points)
        return self.current_patrol_point

    def detect_intruder(self):
        self.intruder_detected = True

class Guard(Agent):
    def __init__(self, env):
        super().__init__(env)
        self.env = env
        self.add(Belief("patrol_point", (0,)))
        self.add(Belief("alert_sent", ("False",)))
        self.add(Goal("patrol", ()))

    @pl(gain, Goal("patrol"), [Belief("patrol_point", (Any,)), Belief("alert_sent", ("False",))])
    def patrol(self, src, current_patrol_point, alert_sent):
        if self.env.intruder_detected:
            self.rm(Belief("patrol_point", (current_patrol_point,)))
            self.add(Belief("patrol_point", (self.env.current_patrol_point,)))
            self.rm(Goal("patrol"))
            self.add(Goal("raise_alert", ()))
        else:
            self.rm(Belief("patrol_point", (current_patrol_point,)))
            new_patrol_point = self.env.move_to_next_patrol_point()
            self.add(Belief("patrol_point", (new_patrol_point,)))
            self.add(Goal("patrol", ()))

    @pl(gain, Goal("raise_alert"), [Belief("alert_sent", ("False",))])
    def raise_alert(self, src, alert_sent):
        self.rm(Belief("alert_sent", ("False",)))
        self.add(Belief("alert_sent", ("True",)))
        self.stop_cycle()

if __name__ == "__main__":
    env = PatrolWorld()
    agent = Guard(env)
    Admin().connect_to([agent], env)
    Admin().start_system()

from maspy import *

class MarketEnv(Environment):
    def __init__(self):
        self.stock = {"apple": 1}

    def get_stock(self, item):
        return self.stock.get(item, 0)

    def reduce_stock(self, item):
        if self.stock[item] > 0:
            self.stock[item] -= 1

class Buyer(Agent):
    def __init__(self, env):
        super().__init__(env)
        self.add(Belief("budget", (10,)))
        self.add(Goal("buy_item", ("apple",)))

    @pl(gain, Goal("buy_item", ("apple",)), Belief("budget", (Any,)))
    def request_item(self, src, budget):
        if budget >= 8:
            self.env.create(Percept("request", ("apple",)))
        else:
            self.rm(Goal("buy_item"))

    @pl(gain, Percept("price", ("apple", 8)))
    def check_price(self, src, item, price):
        if price <= self.get_belief("budget")[0]:
            self.env.create(Percept("purchase", ("apple",)))

    @pl(gain, Percept("sale", ("apple",)))
    def complete_purchase(self, src, item):
        self.add(Belief("owns", ("apple",)))
        self.stop_cycle()

class Seller(Agent):
    def __init__(self, env):
        super().__init__(env)
        self.add(Belief("price", ("apple", 8)))
        self.add(Belief("stock", ("apple", 1)))

    @pl(gain, Percept("request", ("apple",)))
    def respond_to_request(self, src, item):
        self.env.create(Percept("price", (item, 8)))

    @pl(gain, Percept("purchase", ("apple",)), Belief("stock", ("apple", Any)))
    def process_purchase(self, src, item, stock):
        if stock > 0:
            self.env.reduce_stock(item)
            self.env.create(Percept("sale", (item,)))
            self.rm(Belief("stock", (item, stock)))
            self.add(Belief("stock", (item, stock - 1)))

if __name__ == "__main__":
    env = MarketEnv()
    buyer = Buyer(env)
    seller = Seller(env)
    Admin().connect_to([buyer, seller], env)
    Admin().start_system()

