class PatrolWorld(Environment):
    def __init__(self):
        super().__init__()
        self.patrol_points = [0, 1, 2]  # Example patrol points
        self.current_point = 0
        self.intruder_detected = False

    def move_to_next_point(self):
        self.current_point = (self.current_point + 1) % len(self.patrol_points)
        self.create(Percept("patrol_point", (self.current_point,)))

    def detect_intruder(self):
        self.intruder_detected = True
        self.create(Percept("intruder", ("detected",)))

class Guard(Agent):
    def __init__(self, env):
        super().__init__(env)
        self.add(Belief("patrol_point", (0,)))
        self.add(Belief("alert_sent", ("pending",)))
        self.add(Goal("patrol", ()))

    @pl(gain, Goal("patrol", ()), [Belief("patrol_point", (Any,)), Percept("intruder", ("detected",))])
    def raise_alert(self, src, patrol_point):
        self.rm(Belief("patrol_point", (patrol_point,)))
        self.rm(Belief("alert_sent", ("pending",)))
        self.add(Belief("alert_sent", ("sent",)))
        self.stop_cycle()

    @pl(gain, Goal("patrol", ()), Belief("patrol_point", (Any,)))
    def patrol(self, src, patrol_point):
        if self.env.intruder_detected:
            self.rm(Goal("patrol", ()))
        else:
            self.rm(Belief("patrol_point", (patrol_point,)))
            self.env.move_to_next_point()
            new_point = self.env.current_point
            self.add(Belief("patrol_point", (new_point,)))
            self.add(Goal("patrol", ()))

if __name__ == "__main__":
    env = PatrolWorld()
    guard = Guard(env)
    Admin().connect_to([guard], env)
    Admin().start_system()

from maspy import *

class MarketEnv(Environment):
    def __init__(self):
        super().__init__()
        self.stock = {"apple": 1}

    def request_price(self, item):
        if item in self.stock and self.stock[item] > 0:
            return self.get_percept(("price", item))
        return None

    def sell_item(self, item, buyer):
        if item in self.stock and self.stock[item] > 0:
            self.stock[item] -= 1
            buyer.add(Belief("owns", (item,)))
            buyer.rm(Goal("buy_item", (item,)))
            buyer.stop_cycle()
            self.add(Percept("stock", ("apple", self.stock["apple"])))

class Buyer(Agent):
    def __init__(self, env):
        super().__init__(env)
        self.add(Belief("budget", (10,)))
        self.add(Goal("buy_item", ("apple",)))

    @pl(gain, Goal("buy_item", (Any,)), Belief("budget", (Any,)))
    def request_item_price(self, src, item, budget):
        price_percept = self.env.request_price(item)
        if price_percept:
            price = price_percept[1]
            if budget >= price:
                self.add(Goal("purchase_item", (item, price)))

    @pl(gain, Goal("purchase_item", (Any, Any)))
    def purchase_item(self, src, item, price):
        self.env.sell_item(item, self)

class Seller(Agent):
    def __init__(self, env):
        super().__init__(env)
        self.add(Belief("price", ("apple", 8)))
        self.add(Percept("stock", ("apple", 1)))

if __name__ == "__main__":
    env = MarketEnv()
    buyer = Buyer(env)
    seller = Seller(env)
    Admin().connect_to([buyer, seller], env)
    Admin().start_system()

